$(function () {
// Focus on searchModal input when it's shown
$('#searchModal').on('shown.bs.modal', function () {
$('#search-options').focus();
});
// Get elements
const searchOptions = document.getElementById("search-close-options");
const dropdown = document.getElementById("search-dropdown");
const searchInput = document.getElementById("search-options");

// Function to toggle dropdown and search options
const toggleElements = (show) => {
if (show) {
dropdown.classList.add("show");
searchOptions.classList.remove("d-none");
} else {
dropdown.classList.remove("show");
searchOptions.classList.add("d-none");
}
}

// Function to create HTML section
const createHtmlSection = (title, items, icon) => {
let html = `<div class="notification-group-list">
<h5 class="text-overflow text-muted fs-13 mb-2 mt-3 text-uppercase notification-title">${title}</h5>`;
if (title === 'Vulnerabilities') {
items.forEach(item => {
html += `<a href="/vuln/detail/${item.id}" class="list-group-item dropdown-item notify-item">
<i class="mdi ${icon} me-2"></i> <span>${item.title}</span>
</a>`
;
});
} else if (title === 'Products') {
items.forEach(item => {
html += `<a href="${item.get_absolute_url}" class="list-group-item dropdown-item notify-item">
<i class="mdi ${icon} me-2"></i> <span>${item.vendor.name} > ${item.name}</span>
</a>`;
}
);
} else if (title === 'Vendors') {
items.forEach(item => {

html += `<a href="${item.get_absolute_url}" class="list-group-item dropdown-item notify-item">
<i class="mdi ${icon} me-2"></i> <span>${item.name}</span>
</a>`;
});
}
html += '</div>';
return html;
}

// Event listeners
if (searchInput) {
searchInput.addEventListener("focus", () => toggleElements(searchInput.value.length > 0));
searchOptions.addEventListener("click", () => {
searchInput.value = "";
toggleElements(false);
});
document.body.addEventListener("click", (e) => {
if (e.target.getAttribute("id") !== "search-options") toggleElements(false);
});
let timeoutID;
$('#search-options').unbind().keyup(function () {
clearTimeout(timeoutID);
timeoutID = setTimeout(function () {
if (searchInput.value.length > 2) {
$.get('/api/vulnerability/quick-search?q=' + searchInput.value, function (data) {
toggleElements(true);

let html = '<div class="list-group list-group-flush">';
if (data.results.length === 0) {
html += '<div class="notification-group-list"><a href="" class="list-group-item dropdown-item notify-item">No results found</a></div>';
} else if (data.results.errors) {
data.results.errors.forEach((item) => {
html += `<div class="notification-group-list"><a href="" class="list-group-item dropdown-item notify-item"><b>${item.value}</b></a></div>`;
}
);
} else {
data.results.forEach((item) => {
if (item.products) html += createHtmlSection('Products', item.products, 'mdi-alpha-p-box-outline');
if (item.vendors) html += createHtmlSection('Vendors', item.vendors, 'mdi-office-building-outline');
if (item.vulnerabilities) html += createHtmlSection('Vulnerabilities', item.vulnerabilities, 'mdi-bomb');
});
}

html += '</div>';
$('#searchresulstview').html(html);

}, 'json').fail(function () {
$('#searchresulstview').html('<div class="list-group list-group-flush"><a href="" class="list-group-item dropdown-item notify-item">Something went wrong. Contact with hey@cvefeed.io</a></div>');
});
}
}, 500);
});
}
});

